mapper.select:
SELECT a.modl_cd ,e.model_name as modlNm ,a.use_yn ,a.modl_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_fg_cd and comm_grp_cd = 'MODL_FG_CD') modl_fg_nm ,a.modl_os_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_os_fg_cd and comm_grp_cd = 'MODL_OS_FG_CD') modl_os_fg_nm ,a.modl_manufr_fg_cd ,(select cd_nm from ad_comm_cd where comm_cd = a.modl_manufr_fg_cd and comm_grp_cd = 'MODL_MANUFR_FG_CD') modl_manufr_fg_nm ,TO_CHAR(a.stm_last_upd_date,'YYYY.MM.DD HH24:MI') stm_last_upd_date ,(SELECT user_nm FROM ad_user_mst WHERE user_id = a.stm_last_upd_user_id) stm_last_upd_user_nm , a.modl_poc_cd FROM dm_dvc_modl_mst a ,stb_model e WHERE a.modl_cd = e.model_code
AND substr(a.modl_cd,0,2) not in ('11','12')
AND substr(a.modl_cd,0,2) in ('11','12')
AND e.model_name LIKE '%' || UPPER(#{txtModelNm}) || '%'
AND a.modl_fg_cd IN
#{value}
AND a.modl_os_fg_cd IN
#{value}
AND a.modl_manufr_fg_cd IN
#{value}
AND a.use_yn = #{selectUseYn}
ORDER BY a.stm_last_upd_date DESC

SELECT distinct a.modl_cd ,e.model_name as modlNm ,a.modl_poc_cd FROM dm_dvc_modl_mst a , um_sw_dvc_map m , stb_model e WHERE 1=1 AND a.modl_cd = m.modl_cd AND a.modl_cd = e.model_code AND substr(a.modl_cd,0,2) not in ('11','12') AND a.use_yn = 'Y'
AND m.sw_id = #{swId}
ORDER BY e.model_name ASC

SELECT amst.acc_modl_id ,amst.acc_modl_nm ,amst.acc_modl_fg_nm ,amst.modl_manufr_fg_cd ,(select cd_nm from ad_comm_cd where comm_grp_cd='ACC_MODL_MANUFR_FG_CD' and comm_cd = amst.modl_manufr_fg_cd) modl_manufr_fg_nm ,NVL(uuadm.acc_sw_ver, ' ') acc_sw_ver ,amst.modl_introdc_dy ,amst.acc_modl_desc ,amst.use_yn ,amst.stm_last_upd_date ,amst.stm_last_upd_user_id ,NVL((select user_nm from ad_user_mst where user_id = amst.stm_last_upd_user_id), amst.stm_last_upd_user_id) as stmLastUpdUserNm ,amst.acc_sw_fil_modl_nm_loc_start ,amst.acc_sw_fil_modl_nm_loc_end FROM dm_acc_modl_mst amst, (SELECT acc_modl_id, max(acc_sw_ver) acc_sw_ver FROM UM_UPD_ACC_DISTB_MST WHERE ACC_DISTB_STS_FG_CD ='02' GROUP BY acc_modl_id) uuadm WHERE amst.acc_modl_id = uuadm.acc_modl_id (+)
AND amst.acc_modl_nm LIKE '%' || #{txtModelNm} || '%'
AND amst.acc_modl_fg_nm IN
#{value}
AND amst.modl_manufr_fg_cd IN
#{value}
AND amst.use_yn = #{selectUseYn}
ORDER BY amst.stm_last_upd_date DESC

SELECT COUNT(ACC_DISTB_ID) DISTB_CNT
FROM UM_UPD_ACC_DISTB_MST
WHERE ACC_MODL_ID = #{accModlId}

SELECT damm.acc_modl_id ,damm.acc_modl_nm FROM dm_acc_modl_mst damm , um_sw_dvc_map usdm WHERE 1=1 AND usdm.modl_cd = damm.acc_modl_id AND damm.use_yn = 'Y'
AND usdm.sw_id = #{swId}
ORDER BY damm.acc_modl_nm ASC
